import React from "react";
import {
  FileSpreadsheet,
  User,
  FileImage,
  Atom,
  Database,
  Sparkles,
  Brush,
  Cog,
  Monitor,
  BarChart3,
  TrendingUp,
  PieChart,
  FileText,
  FileType,
  Clock,
  Workflow,
  Bell,
  Mail,
} from "lucide-react";

const Card = ({ children, className = "" }) => (
  <div
    className={`bg-white rounded-2xl shadow-sm border border-slate-100 ${className}`}
    style={{ boxShadow: "0 2px 8px rgba(30,41,59,0.06)" }}
  >
    {children}
  </div>
);

const CardHeader = ({ icon, title }) => (
  <div className="flex items-center gap-2 px-5 pt-5 pb-3">
    {icon}
    <h3 className="font-bold text-[15px] text-slate-800 leading-tight">
      {title}
    </h3>
  </div>
);

const ListItem = ({ icon, children, bold = false }) => (
  <div className="flex items-center gap-2 px-5 py-1.5">
    {icon}
    <span
      className={`text-[13px] ${
        bold ? "font-semibold text-slate-800" : "text-slate-600"
      }`}
    >
      {children}
    </span>
  </div>
);

const Bullet = ({ children }) => (
  <div className="flex items-start gap-2 px-5 py-1">
    <span className="text-slate-400 mt-1.5 text-[8px]">●</span>
    <span className="text-[13px] text-slate-600">{children}</span>
  </div>
);

const Arrow = ({ direction = "right", className = "" }) => {
  const rotations = {
    right: "rotate-0",
    down: "rotate-90",
    left: "rotate-180",
    up: "-rotate-90",
  };
  return (
    <svg
      className={`${rotations[direction]} ${className}`}
      width="28"
      height="14"
      viewBox="0 0 28 14"
      fill="none"
    >
      <line
        x1="0"
        y1="7"
        x2="22"
        y2="7"
        stroke="#334155"
        strokeWidth="1.5"
      />
      <path d="M22 2 L27 7 L22 12" stroke="#334155" strokeWidth="1.5" fill="none" />
    </svg>
  );
};

export default function ArchitectureDiagram() {
  return (
    <div className="w-full min-h-screen bg-slate-50 flex items-center justify-center p-6">
      <div className="relative w-full max-w-[1200px]">
        {/* Middle band background */}
        <div
          className="absolute rounded-[28px] bg-slate-100/70"
          style={{ top: "265px", left: "245px", right: "245px", bottom: "20px" }}
        />

        {/* Grid layout */}
        <div className="relative grid grid-cols-4 gap-6" style={{ gridTemplateRows: "auto auto auto" }}>
          {/* Row 1 */}
          {/* Sources */}
          <Card className="col-start-1 row-start-1 py-1">
            <CardHeader icon={null} title="Sources" />
            <div className="pb-4">
              <ListItem
                icon={
                  <span className="inline-flex items-center justify-center w-6 h-4 bg-sky-500 text-white text-[8px] font-bold rounded-sm">
                    SAP
                  </span>
                }
                bold
              >
                SAP C4C
              </ListItem>
              <ListItem
                icon={<FileSpreadsheet size={18} className="text-emerald-600" />}
                bold
              >
                Excel Upload
              </ListItem>
              <ListItem
                icon={<User size={18} className="text-slate-500" />}
                bold
              >
                Manual Data
                <br />
                Entry
              </ListItem>
              <ListItem
                icon={<FileImage size={18} className="text-orange-400" />}
                bold
              >
                Documents &amp;
                <br />
                Media
              </ListItem>
            </div>
          </Card>

          {/* React App */}
          <Card className="col-start-2 row-start-1 py-1">
            <div className="flex flex-col items-center pt-5 pb-2">
              <Atom size={30} className="text-sky-500" />
              <h3 className="font-bold text-[15px] text-slate-800 mt-1">
                React App
              </h3>
            </div>
            <div className="pb-4">
              <Bullet>Data Entry UI</Bullet>
              <Bullet>File Upload UI</Bullet>
              <Bullet>Validation Rules</Bullet>
              <Bullet>Approval Workflow</Bullet>
            </div>
          </Card>

          {/* DOMO Filesets */}
          <Card className="col-start-3 row-start-1 py-1">
            <div className="flex flex-col items-center pt-5 pb-2">
              <Database size={30} className="text-sky-500" />
              <h3 className="font-bold text-[15px] text-slate-800 mt-1">
                DOMO Filesets
              </h3>
            </div>
            <div className="pb-4">
              <Bullet>Excel Files</Bullet>
              <Bullet>Documents</Bullet>
              <Bullet>Videos / Media</Bullet>
              <Bullet>Manual Entry Data</Bullet>
            </div>
          </Card>

          {/* Export PDF / PPT */}
          <Card className="col-start-4 row-start-1 row-span-2 py-1 self-start">
            <CardHeader icon={null} title="Export PDF / PPT" />
            <div className="pb-4">
              <ListItem
                icon={<FileType size={18} className="text-red-600" />}
                bold
              >
                PDF Export
              </ListItem>
              <ListItem
                icon={<FileType size={18} className="text-red-500" />}
                bold
              >
                PowerPoint Export
              </ListItem>
              <ListItem
                icon={<FileSpreadsheet size={18} className="text-emerald-600" />}
                bold
              >
                Excel Export
              </ListItem>
              <ListItem
                icon={<Clock size={18} className="text-slate-500" />}
                bold
              >
                Scheduled Reports
              </ListItem>
            </div>
          </Card>

          {/* Row 2 */}
          {/* Workflow */}
          <Card className="col-start-1 row-start-2 py-1 self-start">
            <CardHeader
              icon={<Workflow size={22} className="text-sky-500" />}
              title="Workflow"
            />
            <div className="pb-4">
              <Bullet>Alerts</Bullet>
              <Bullet>Notifications</Bullet>
            </div>
          </Card>

          {/* DOMO Datasets (raw) */}
          <Card className="col-start-2 row-start-2 py-1">
            <div className="flex flex-col items-center pt-5 pb-2">
              <Database size={30} className="text-sky-500" />
              <h3 className="font-bold text-[15px] text-slate-800 mt-1">
                DOMO Datasets
              </h3>
            </div>
            <div className="pb-4">
              <Bullet>Excel Files</Bullet>
              <Bullet>Documents</Bullet>
              <Bullet>Videos / Media</Bullet>
              <Bullet>Manual Entry Data</Bullet>
            </div>
          </Card>

          {/* Magic ETL / DataFlows */}
          <Card className="col-start-3 row-start-2 py-1">
            <CardHeader
              icon={
                <span className="inline-flex -space-x-1">
                  <Sparkles size={18} className="text-sky-500" />
                  <span className="w-2 h-2 rounded-full bg-red-400 -ml-1" />
                </span>
              }
              title="Magic ETL / DataFlows"
            />
            <div className="pb-4">
              <ListItem icon={<Brush size={18} className="text-sky-500" />}>
                Data Cleansing
              </ListItem>
              <ListItem icon={null}>
                <span className="ml-[26px]">Data Validation</span>
              </ListItem>
              <ListItem icon={<Cog size={18} className="text-slate-500" />}>
                Business Rules
              </ListItem>
              <ListItem icon={null}>
                <span className="ml-[26px]">Source Integration</span>
              </ListItem>
            </div>
          </Card>

          {/* Row 3 */}
          {/* Email Distribution */}
          <Card className="col-start-1 row-start-3 py-1 self-start">
            <CardHeader
              icon={<Mail size={22} className="text-sky-500" />}
              title="Email"
            />
            <div className="-mt-3 pb-4 px-5">
              <span className="font-bold text-[15px] text-slate-800">
                Distribution
              </span>
            </div>
          </Card>

          {/* DOMO Datasets (governed) */}
          <Card className="col-start-2 row-start-3 py-1 self-start">
            <CardHeader icon={null} title="DOMO Datasets" />
            <div className="pb-4">
              <Bullet>Governed Storage</Bullet>
              <Bullet>Business-Ready Data</Bullet>
            </div>
          </Card>

          {/* Dashboard */}
          <Card className="col-start-3 row-start-3 py-1 self-start">
            <div className="flex items-center gap-3 px-5 pt-5 pb-3">
              <div className="grid grid-cols-2 gap-1">
                <Monitor size={20} className="text-sky-500" />
                <TrendingUp size={20} className="text-red-500" />
                <BarChart3 size={20} className="text-emerald-600" />
                <PieChart size={20} className="text-sky-400" />
              </div>
              <h3 className="font-bold text-[15px] text-slate-800">
                Dashboard
              </h3>
            </div>
            <div className="pb-4">
              <Bullet>Executive Dashboard</Bullet>
              <Bullet>Operational Dashboard</Bullet>
            </div>
          </Card>
        </div>

        {/* Arrows - absolutely positioned */}
        {/* Sources -> React App */}
        <div className="absolute" style={{ top: "70px", left: "218px" }}>
          <Arrow direction="right" />
        </div>
        {/* React App -> DOMO Filesets */}
        <div className="absolute" style={{ top: "70px", left: "515px" }}>
          <Arrow direction="right" />
        </div>
        {/* React App -> DOMO Datasets (down) */}
        <div className="absolute" style={{ top: "255px", left: "365px", transform: "rotate(90deg)" }}>
          <Arrow direction="right" />
        </div>
        {/* DOMO Filesets -> Magic ETL (down) */}
        <div className="absolute" style={{ top: "255px", left: "660px", transform: "rotate(90deg)" }}>
          <Arrow direction="right" />
        </div>
        {/* DOMO Filesets -> Magic ETL (curved via right side, matches image's right elbow) */}
